module RefModule(
    input [7:0] a,
    input [7:0] b,
    output reg [15:0] result
);reg [15:0] final_sig;
    reg [3:0] i;

    always @(*) begin
        final_sig = 0;
        for (i = 0; i < 8; i = i + 1) begin
            if (b[i] == 1) begin
                final_sig = final_sig + (a << i);
            end
        end
        result = final_sig;
    end

endmodule
